var e=JSON.parse(`[{"id":"L3_1","type":"dialog","speaker":"SUYEON_COFFIN_SUMMER_NULL","text":{"KOREA":"……그래서 여기 오게 된 겁니다.","JPN":"……それでここに来たわけです。","ENG":"... So that’s how we got here.","TWN":"…所以才會來到這裡。"},"stage":{"bg":"FOREST_NORMAL","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SUYEON_COFFIN_SUMMER_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"MACHINEGAP_COFFIN_NULL_NULL","face":"UNIT_DESPAIR"}}}},{"id":"L4_1","type":"dialog","speaker":"SUYEON_COFFIN_SUMMER_NULL","text":{"KOREA":"이제 궁금증은 전부 풀렸나요, 모네 양?","JPN":"これで疑問が解けましたか、モネさん？","ENG":"Is your curiosity satisfied, Mone?","TWN":"現在你的問題都問完了嗎？莫妮？"},"stage":{"bg":"FOREST_NORMAL","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SUYEON_COFFIN_SUMMER_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"MACHINEGAP_COFFIN_NULL_NULL","face":"UNIT_DESPAIR"}}}},{"id":"L6_1","type":"dialog","speaker":"TONFA_FLORA_SUMMER_NULL","text":{"KOREA":"넵! 확실하게 알아들었지 말임다!","JPN":"はいっ！　わかったっす！","ENG":"Yes, ma’am! Crystal clear!","TWN":"是！都聽明白了唷！"},"stage":{"bg":"FOREST_NORMAL","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"TONFA_FLORA_SUMMER_NULL","face":"UNIT_PRIDE"},"R":null}}},{"id":"L7_1","type":"dialog","speaker":"TONFA_FLORA_SUMMER_NULL","text":{"KOREA":"주인님께선 역시 사나이답슴다! 부사장님을 위해 이렇게 멀리까지 오시다니!","JPN":"ご主人様は男前っすね！　副社長のためにこんな遠くまで来るなんて！","ENG":"You’re the best, Master! You came this far for the Vice President!","TWN":"主人果然是個男子漢大丈唷！為了副總還跑到這麼遠的地方！"},"stage":{"bg":"FOREST_NORMAL","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"TONFA_FLORA_SUMMER_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L10_1","type":"dialog","speaker":"SUYEON_COFFIN_SUMMER_NULL","text":{"KOREA":"그래요. 휴가 첫날부터 꼬일 대로 꼬였지만요.","JPN":"そうですね。休み初日からうまくいかないことばかりでしたが。","ENG":"Yes. Though nothing has been working right from day one.","TWN":"對啊，雖然從度假第一天就開始惹麻煩。"},"stage":{"bg":"FOREST_NORMAL","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SUYEON_COFFIN_SUMMER_NULL","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"MACHINEGAP_COFFIN_NULL_NULL","face":"UNIT_DESPAIR"}}}},{"id":"L12_1","type":"dialog","speaker":"TONFA_FLORA_SUMMER_NULL","text":{"KOREA":"걱정 마십셔. 모네네 동네에서 푹 쉬시면 됨다.","JPN":"もう心配ないっす。これからはモネの村でゆっくりしてくださいっす！","ENG":"Don’t worry about it, ma’am. You’ll be able to enjoy your vacation in my hometown.","TWN":"請不要擔心，在莫妮的村裡好好休息吧！"},"stage":{"bg":"FOREST_NORMAL","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"TONFA_FLORA_SUMMER_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L13_1","type":"dialog","speaker":"TONFA_FLORA_SUMMER_NULL","text":{"KOREA":"메이드장님도 지내시는 동안 정말 조용하고 멋진 곳이라고 칭찬해 주셨지 말임다.","JPN":"メイド長もここにいた時は、本当に静かで素敵な場所と褒めてくれたっす。","ENG":"The Chief Maid also commented that it was a relaxing, peaceful town, ma’am.","TWN":"女僕長之前住在這裡時，也說這裡很安靜，是個很棒的地方唷！"},"stage":{"bg":"FOREST_NORMAL","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"TONFA_FLORA_SUMMER_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L16_1","type":"dialog","speaker":"MACHINEGAP_COFFIN_NULL_NULL","text":{"KOREA":"허억…… 허억……","JPN":"はあ……はあ……","ENG":"*Huff... Huff...*","TWN":"呼呼…呼呼…"},"stage":{"bg":"FOREST_NORMAL","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SUYEON_COFFIN_SUMMER_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"MACHINEGAP_COFFIN_NULL_NULL","face":"UNIT_DESPAIR"}}}},{"id":"L17_1","type":"dialog","speaker":"MACHINEGAP_COFFIN_NULL_NULL","text":{"KOREA":"모, 모네 양, 그래서 마을은 대체 언제쯤이면 도착하는 건가?","JPN":"モ、モネ。それで村にはいったいいつ頃着くのかね？","ENG":"M-Mone... How much longer?","TWN":"莫…莫妮，還要多久才會到你家啊？"},"stage":{"bg":"FOREST_NORMAL","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SUYEON_COFFIN_SUMMER_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"MACHINEGAP_COFFIN_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L19_1","type":"dialog","speaker":"TONFA_FLORA_SUMMER_NULL","text":{"KOREA":"거의 다 왔슴다! 이 언덕만 넘어가면 됨다!","JPN":"あと少しっす！　この丘を越えるだけっす！","ENG":"We’re almost there, sir! It’s right over this hill!","TWN":"快到了唷！ 翻過這個山坡就到囉！"},"stage":{"bg":"FOREST_NORMAL","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"TONFA_FLORA_SUMMER_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L22_1","type":"dialog","speaker":"MACHINEGAP_COFFIN_NULL_NULL","text":{"KOREA":"벌써 해발 500미터는 올라온 것 같은데, 이게 언덕이라고……?","JPN":"もう標高500メートルは登った気がするが、これが丘だと……？","ENG":"I think we’re almost at 500 meters altitude now. You call this a hill?","TWN":"我們根本爬到海拔5000公尺了吧，這是哪門子山坡……？"},"stage":{"bg":"FOREST_NORMAL","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SUYEON_COFFIN_SUMMER_NULL","face":"UNIT_LAUGH"},"C":null,"R":{"char_id":"MACHINEGAP_COFFIN_NULL_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L23_1","type":"dialog","speaker":"SUYEON_COFFIN_SUMMER_NULL","text":{"KOREA":"저렇게 기운이 넘치는 건 환경 덕분인가 보군요.","JPN":"あんなに元気いっぱいなのは育った環境のおかげでしょう。","ENG":"I guess she’s full of energy thanks to this hill.","TWN":"她這麼體力這麼好，應該是因為住在山裡的關係吧？"},"stage":{"bg":"FOREST_NORMAL","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SUYEON_COFFIN_SUMMER_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"MACHINEGAP_COFFIN_NULL_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L25_1","type":"dialog","speaker":"MACHINEGAP_COFFIN_NULL_NULL","text":{"KOREA":"응?","JPN":"ん？","ENG":"Huh?","TWN":"嗯？"},"stage":{"bg":"FOREST_NORMAL","bgm":"CUTSCEN_FOREST_LOOP","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SUYEON_COFFIN_SUMMER_NULL","face":"UNIT_HATE"},"C":null,"R":{"char_id":"MACHINEGAP_COFFIN_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L26_1","type":"dialog","speaker":"MACHINEGAP_COFFIN_NULL_NULL","text":{"KOREA":"부사장, 방금 무슨 소리가 들리지 않았나?","JPN":"副社長、今何か聞こえなかったか？","ENG":"Vice President, did you hear that?","TWN":"副總，你剛有聽到什麼聲音嗎？"},"stage":{"bg":"FOREST_NORMAL","bgm":"CUTSCEN_FOREST_LOOP","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SUYEON_COFFIN_SUMMER_NULL","face":"UNIT_HATE"},"C":null,"R":{"char_id":"MACHINEGAP_COFFIN_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L27_1","type":"dialog","speaker":"SUYEON_COFFIN_SUMMER_NULL","text":{"KOREA":"네. 총성이었습니다.","JPN":"はい、銃声でしたね。","ENG":"Yes, it was a gunshot.","TWN":"有，是槍聲。"},"stage":{"bg":"FOREST_NORMAL","bgm":"CUTSCEN_FOREST_LOOP","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SUYEON_COFFIN_SUMMER_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"MACHINEGAP_COFFIN_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L28_1","type":"dialog","speaker":"SUYEON_COFFIN_SUMMER_NULL","text":{"KOREA":"정확하진 않지만 언덕 너머에서 들린 것 같군요.","JPN":"確かではありませんが、丘の向こうから聞こえたようです。","ENG":"I think it came from the other side of the hill.","TWN":"雖然不是很確定，似乎從山坡那邊傳來的。"},"stage":{"bg":"FOREST_NORMAL","bgm":"CUTSCEN_FOREST_LOOP","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SUYEON_COFFIN_SUMMER_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"MACHINEGAP_COFFIN_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L30_1","type":"dialog","speaker":"TONFA_FLORA_SUMMER_NULL","text":{"KOREA":"그럼 마을에서 누가 총을 쐈다는 검까?!","JPN":"え、誰かが村で銃を撃ったってことっすか！？","ENG":"So you’re saying that someone in the village shot a gun, ma’am?","TWN":"是有人在村裡開槍的意思嗎？"},"stage":{"bg":"FOREST_NORMAL","bgm":"CUTSCEN_FOREST_LOOP","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"TONFA_FLORA_SUMMER_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L31_1","type":"dialog","speaker":"TONFA_FLORA_SUMMER_NULL","text":{"KOREA":"죄송함다, 주인님! 모네 먼저 가겠슴다! 엄니가 다칠지도 모름다!","JPN":"すみません、ご主人様！　モネは先に行きます！　母ちゃんが心配っす！","ENG":"I’m sorry, Master! I have to go now! My mama might be in danger!","TWN":"很抱歉，主人，莫妮要先走一步！我擔心媽媽會受傷！"},"stage":{"bg":"FOREST_NORMAL","bgm":"CUTSCEN_FOREST_LOOP","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"TONFA_FLORA_SUMMER_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L33_1","type":"dialog","speaker":"LARA_NPC_NULL_NULL","text":{"KOREA":"잠깐만요! 뛰어가면 늦어요!","JPN":"待ってください、走って行っても間に合いません！","ENG":"Wait! You won’t make it in time on foot!","TWN":"等等！用跑的太慢了！"},"stage":{"bg":"FOREST_NORMAL","bgm":"CUTSCEN_FOREST_LOOP","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LARA_NPC_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L34_1","type":"dialog","speaker":"LARA_NPC_NULL_NULL","text":{"KOREA":"제 등에 업히세요! 번개보다 빠르게 배송해 드릴게요!","JPN":"私がおんぶします！　稲妻よりも早くお届けしますので！","ENG":"Climb on my back! I’ll deliver you to the village super fast!","TWN":"我揹你吧！我會用光速把你送到家！"},"stage":{"bg":"FOREST_NORMAL","bgm":"CUTSCEN_FOREST_LOOP","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LARA_NPC_NULL_NULL","face":"UNIT_PRIDE"},"R":null}}},{"id":"L39_1","type":"dialog","speaker":"PMC_SUMMER_NULL_L","text":{"KOREA":"지금 우리가 지금 농담하는 걸로 보여?","JPN":"俺らの話が冗談に聞こえるか？","ENG":"You think we’re joking?","TWN":"我們像是在開玩笑嗎？"},"stage":{"bg":"VILLAGE1","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"PMC_SUMMER_NULL_A","face":"UNIT_IDLE"},"C":{"char_id":"PMC_SUMMER_NULL_L","face":"UNIT_IDLE"},"R":{"char_id":"PMC_SUMMER_NULL_B","face":"UNIT_IDLE"}}},"sfx":"FX_COMBAT_ALL_FOOT_STEP_LANDING_SMALL_02"},{"id":"L40_1","type":"dialog","speaker":"PMC_SUMMER_NULL_L","text":{"KOREA":"보상금도 두둑하게 준다잖아. 왜 이렇게 억지를 부려.","JPN":"補償金も手厚くやると言ってるじゃないか。なぜここまで意地を張るんだ。","ENG":"I promised you a generous reward. Why do you resist?","TWN":"不是說會給大一筆補償金嗎？爲什麼還賴在這裡不走？"},"stage":{"bg":"VILLAGE1","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"PMC_SUMMER_NULL_A","face":"UNIT_IDLE"},"C":{"char_id":"PMC_SUMMER_NULL_L","face":"UNIT_IDLE"},"R":{"char_id":"PMC_SUMMER_NULL_B","face":"UNIT_IDLE"}}}},{"id":"L41_1","type":"dialog","speaker":"PMC_SUMMER_NULL_L","text":{"KOREA":"너도 아직 어려 보이는데, 이딴 깡촌에서 살다 죽긴 싫을 거 아냐?","JPN":"まだだいぶ若いように見えるが、こんなド田舎で一生暮らして死にたくねえだろ？","ENG":"You’re young, you don’t want to live in this middle of nowhere village forever.","TWN":"你看起來也還年輕，應該也不想一輩子窩在這個鳥不生蛋的地方吧？"},"stage":{"bg":"VILLAGE1","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"PMC_SUMMER_NULL_A","face":"UNIT_IDLE"},"C":{"char_id":"PMC_SUMMER_NULL_L","face":"UNIT_IDLE"},"R":{"char_id":"PMC_SUMMER_NULL_B","face":"UNIT_IDLE"}}}},{"id":"L43_1","type":"dialog","speaker":"MONEMOTHER_NPC_NULL_Q","text":{"KOREA":"싫지 않아요.","JPN":"一生ここでもいいです。","ENG":"I like this village.","TWN":"我沒這麼說。"},"stage":{"bg":"VILLAGE1","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MONEMOTHER_NPC_NULL_Q","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L44_1","type":"dialog","speaker":"MONEMOTHER_NPC_NULL_Q","text":{"KOREA":"저도, 다른 어르신들도 이 마을을 사랑해요. 그래서 당신들을 막으려고 하는 거고요.","JPN":"私も他のみんなも、この村のことを愛しています。だからあなたたちを止めたいのです。","ENG":"Me and my neighbors all love this village. That’s why we’re trying to stop you.","TWN":"我和其他長輩都愛這個地方，不准你們在這裡撒野。"},"stage":{"bg":"VILLAGE1","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MONEMOTHER_NPC_NULL_Q","face":"UNIT_IDLE"},"R":null}}},{"id":"L45_1","type":"dialog","speaker":"MONEMOTHER_NPC_NULL_Q","text":{"KOREA":"얼마를 주신다고 해도 저희들 대답은 같아요. 이 마을은 넘겨 드릴 수 없어요.","JPN":"いくら提示されても私たちの答えは変わりません。この村は渡しません。","ENG":"We don’t care how much you pay us. We’re not giving you this town.","TWN":"不管你們給多少錢，我們的答案都是一樣的，這個村子是絕不能交給你們的。"},"stage":{"bg":"VILLAGE1","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MONEMOTHER_NPC_NULL_Q","face":"UNIT_IDLE"},"R":null}}},{"id":"L49_1","type":"dialog","speaker":"PMC_SUMMER_NULL_L","text":{"KOREA":"쳇, 끝까지 귀찮게 구는군.","JPN":"ちっ、手間取らせやがって。","ENG":"Tsk, this is bothersome.","TWN":"嗟，真是麻煩。"},"stage":{"bg":"VILLAGE1","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"PMC_SUMMER_NULL_A","face":"UNIT_IDLE"},"C":{"char_id":"PMC_SUMMER_NULL_L","face":"UNIT_IDLE"},"R":{"char_id":"PMC_SUMMER_NULL_B","face":"UNIT_IDLE"}}}},{"id":"L50_1","type":"dialog","speaker":"PMC_SUMMER_NULL_A","text":{"KOREA":"어떡할까요, 대장?","JPN":"どうしますか、隊長？","ENG":"What do we do, boss?","TWN":"怎麼辦呢，隊長？"},"stage":{"bg":"VILLAGE1","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"PMC_SUMMER_NULL_A","face":"UNIT_IDLE"},"C":{"char_id":"PMC_SUMMER_NULL_L","face":"UNIT_IDLE"},"R":{"char_id":"PMC_SUMMER_NULL_B","face":"UNIT_IDLE"}}}},{"id":"L1_1","type":"dialog","speaker":"PMC_SUMMER_NULL_B","text":{"KOREA":"오늘도 빈손으로 물러났다간 의뢰주한테 할말이 없습니다.","JPN":"今日も収穫なしで帰ったら依頼主に合わせる顔がありません。","ENG":"Our client won’t like it if we just pull out today with nothing.","TWN":"今天也空手而歸的話，對委託人不好交代啊。"},"stage":{"bg":"VILLAGE1","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"PMC_SUMMER_NULL_A","face":"UNIT_IDLE"},"C":{"char_id":"PMC_SUMMER_NULL_L","face":"UNIT_IDLE"},"R":{"char_id":"PMC_SUMMER_NULL_B","face":"UNIT_IDLE"}}}},{"id":"L2_1","type":"dialog","speaker":"PMC_SUMMER_NULL_L","text":{"KOREA":"그건 내가 제일 잘 알아. 드라코는 어디 있지?","JPN":"それは俺が一番わかっている。ドラコはどこにいる？","ENG":"I know that already. Where is Dracasia?","TWN":"這我當然知道！德拉克人呢？"},"stage":{"bg":"VILLAGE1","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"PMC_SUMMER_NULL_A","face":"UNIT_IDLE"},"C":{"char_id":"PMC_SUMMER_NULL_L","face":"UNIT_IDLE"},"R":{"char_id":"PMC_SUMMER_NULL_B","face":"UNIT_IDLE"}}}},{"id":"L3_1","type":"dialog","speaker":"PMC_SUMMER_NULL_A","text":{"KOREA":"그게…… 또 셀카 찍는다고 어디론가 사라졌습니다.","JPN":"それが……自撮りをすると言って、どこかに消えました。","ENG":"Um... She went away to take a selfie.","TWN":"嗯…不知道又跑到哪裡去拍網美照了。"},"stage":{"bg":"VILLAGE1","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"PMC_SUMMER_NULL_A","face":"UNIT_IDLE"},"C":{"char_id":"PMC_SUMMER_NULL_L","face":"UNIT_IDLE"},"R":{"char_id":"PMC_SUMMER_NULL_B","face":"UNIT_IDLE"}}}},{"id":"L4_1","type":"dialog","speaker":"PMC_SUMMER_NULL_L","text":{"KOREA":"젠장, 프론트 베이 출신이라길래 비싼 돈 주고 데려왔더니……","JPN":"クソっ、フロントベイ出身と聞いたから大金を払って雇ったのに……","ENG":"Darn it, we paid her so much money only because she was from Front Bay...","TWN":"真是的，因為是前灣出身的，我還高價把她請來…"},"stage":{"bg":"VILLAGE1","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"PMC_SUMMER_NULL_A","face":"UNIT_IDLE"},"C":{"char_id":"PMC_SUMMER_NULL_L","face":"UNIT_IDLE"},"R":{"char_id":"PMC_SUMMER_NULL_B","face":"UNIT_IDLE"}}}},{"id":"L5_1","type":"dialog","speaker":"PMC_SUMMER_NULL_L","text":{"KOREA":"시간 없으니 우리끼리 진행한다! 저 여자애랑 늙은이들 전부 끌어내!","JPN":"時間もないし俺らだけで始めるぞ！　あの女の子と老いぼれを全員追い出せ！","ENG":"We don’t have the time, we’ll just proceed without her. Pull that girl and old timers out of the way!","TWN":"沒時間了，我們自己動手吧！把那女孩和老頭子都拉出去！"},"stage":{"bg":"VILLAGE1","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"PMC_SUMMER_NULL_A","face":"UNIT_IDLE"},"C":{"char_id":"PMC_SUMMER_NULL_L","face":"UNIT_IDLE"},"R":{"char_id":"PMC_SUMMER_NULL_B","face":"UNIT_IDLE"}}}},{"id":"L7_1","type":"dialog","speaker":"GRANDFA_NPC_SUMMER_NULL","text":{"KOREA":"이, 이것들이! 당장 내려놓지 못해!","JPN":"こ、こいつら！　離せ！","ENG":"H-how dare you! Release me!","TWN":"你們這些傢伙！立刻把我放下來！"},"stage":{"bg":"VILLAGE1","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L8_1","type":"dialog","speaker":"PMC_SUMMER_NULL_NULL","text":{"KOREA":"아, 영감님들! 일 복잡하게 만들지 말고 좀 갑시다!","JPN":"ったく。おい、じじい！　こっちだって手荒な真似はしたくねえからさっさと動けよ！","ENG":"Hey, old timers! Don’t make things complicated!","TWN":"我說老頭子！配合點，大家好辦事。"},"stage":{"bg":"VILLAGE1","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L9_1","type":"dialog","speaker":"GRANDMA_NPC_SUMMER_NULL","text":{"KOREA":"어딜 손 대, 젊은 사람들이! 나도 왕년에 날리던 몸이야!","JPN":"どこを触ってるのじゃ！　わしゃこうみえて昔は凄腕だったんだぞ！","ENG":"Don’t touch me! I used to be heck of a fighter when I was young!","TWN":"給我放尊重點，年輕人！你們也會老的！"},"stage":{"bg":"VILLAGE1","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L11_1","type":"dialog","speaker":"MONEMOTHER_NPC_NULL_Q","text":{"KOREA":"기다려요! 어르신들한테 무슨 짓을……!","JPN":"お待ちください！　か弱い年寄りになんの真似ですか……！","ENG":"Stop! Show some respect to your elders!","TWN":"等一下！你們竟敢對長輩…？"},"stage":{"bg":"VILLAGE1","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MONEMOTHER_NPC_NULL_Q","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L13_1","type":"dialog","speaker":"PMC_SUMMER_NULL_L","text":{"KOREA":"어르신인데, 뭐? 우리가 무슨 요양원 돌보미들인 줄 알아?","JPN":"か弱い年寄り？　俺らは老人ホームの介護士じゃないんだぞ！","ENG":"Elders? Do you think we’re from some sort of old folks' home?","TWN":"長輩又怎麼樣？我們像養老院的看護嗎？"},"stage":{"bg":"VILLAGE1","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"PMC_SUMMER_NULL_L","face":"UNIT_IDLE"},"R":null}},"sfx":"FX_COMBAT_ALL_MISSILE_RELOAD"},{"id":"L14_1","type":"dialog","speaker":"PMC_SUMMER_NULL_L","text":{"KOREA":"우리도 참을 만큼 참았어. 더 성가시게 굴면 정말로 쏴 버린다.","JPN":"もう我慢の限界だ。これ以上手こずらせたら撃つぞ。","ENG":"We gave you enough time. Stop resisting, otherwise you’ll actually get shot this time.","TWN":"給臉不要臉，再吵我就開槍囉！"},"stage":{"bg":"VILLAGE1","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"PMC_SUMMER_NULL_L","face":"UNIT_IDLE"},"R":null}}},{"id":"L16_1","type":"dialog","speaker":"MONEMOTHER_NPC_NULL_Q","text":{"KOREA":"당신들, 이런 짓을 하고도 무사할 것 같아요?! 당장 경찰에 신고하겠어요!","JPN":"あなたたち、こんなことをしてタダで済むと思ってるんですか？　今すぐ警察に通報します！","ENG":"You’ll never get away with this! I’ll call the cops!","TWN":"你們以為做這種事還能全身而退嗎？！ 我馬上報警！"},"stage":{"bg":"VILLAGE1","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MONEMOTHER_NPC_NULL_Q","face":"UNIT_HATE"},"R":null}}},{"id":"L17_1","type":"dialog","speaker":"PMC_SUMMER_NULL_L","text":{"KOREA":"어디 해 보시지. 어차피 그놈들도 돈다발 먹여 주는 쪽 편을 들 테니까.","JPN":"やってみろ。どうせ奴らも金で動く連中だからこっちの味方なんだぜ？","ENG":"Please do. I’m sure they’ll love our money.","TWN":"報啊，沒聽過有錢能使鬼推磨嗎？"},"stage":{"bg":"VILLAGE1","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"PMC_SUMMER_NULL_L","face":"UNIT_IDLE"},"R":null}}},{"id":"L18_1","type":"dialog","speaker":"PMC_SUMMER_NULL_L","text":{"KOREA":"윽, 뭐야? 모래 바람……?","JPN":"うっ、なんだ？　砂嵐……？","ENG":"Urgh, what is this? A sandstorm...?","TWN":"呃，搞什麼？沙塵暴…？"},"stage":{"bg":"VILLAGE1","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"PMC_SUMMER_NULL_L","face":"UNIT_IDLE"},"R":null}},"sfx":"FX_CUTSCEN_WIND"},{"id":"L19_1","type":"dialog","speaker":"TONFA_FLORA_SUMMER_NULL","text":{"KOREA":"아네모네 펀─치!","JPN":"アネモネパ～ンチ！！","ENG":"Anemone Puuunch!","TWN":"必殺銀蓮花─拳！"},"stage":{"bg":"VILLAGE1","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"TONFA_FLORA_SUMMER_NULL","face":"UNIT_PRIDE"},"R":null}}},{"id":"L21_1","type":"dialog","speaker":"PMC_SUMMER_NULL_L","text":{"KOREA":"어, 어디서 갑자기 나타난 거야, 이 꼬맹이!","JPN":"ど、どこから出てきやがった、このガキ！","ENG":"W-where did this kid come from?","TWN":"你從哪冒出來的，小鬼！"},"stage":{"bg":"VILLAGE1","bgm":"CSM_BATTLE_NORMAL0","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"PMC_SUMMER_NULL_L","face":"UNIT_IDLE"},"R":null}}},{"id":"L22_1","type":"dialog","speaker":"MONEMOTHER_NPC_NULL_Q","text":{"KOREA":"모네야?!","JPN":"モネ！？","ENG":"Mone?!","TWN":"莫妮？！"},"stage":{"bg":"VILLAGE1","bgm":"CSM_BATTLE_NORMAL0","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MONEMOTHER_NPC_NULL_Q","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L25_1","type":"dialog","speaker":"LARA_NPC_NULL_NULL","text":{"KOREA":"정시 도착! 배송 완료했습니다! 에취!","JPN":"定時到着！　配送完了でーす！　はくしょん！","ENG":"Right on time! Delivery complete! Achoo!","TWN":"準時送達！配送完畢！哈啾！"},"stage":{"bg":"VILLAGE1","bgm":"CSM_BATTLE_NORMAL0","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"LARA_NPC_NULL_NULL","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"TONFA_FLORA_SUMMER_NULL","face":"UNIT_SERIOUS"}}}},{"id":"L26_1","type":"dialog","speaker":"TONFA_FLORA_SUMMER_NULL","text":{"KOREA":"갑자기 우리 동네에 쳐들어와서 무슨 짓임까! 사람들을 괴롭히는 건 나쁜 짓이지 말임다!","JPN":"急にうちの村に来て何してるっすか！　人をいじめるのは悪いことっすよ！","ENG":"What are you sirs doing in my village? Harassing people is bad!","TWN":"怎麼可以突然闖進別人家呢？欺負人是不好的唷！"},"stage":{"bg":"VILLAGE1","bgm":"CSM_BATTLE_NORMAL0","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"LARA_NPC_NULL_NULL","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"TONFA_FLORA_SUMMER_NULL","face":"UNIT_IDLE"}}}},{"id":"L28_1","type":"dialog","speaker":"TONFA_FLORA_SUMMER_NULL","text":{"KOREA":"빨리 우리 엄니한테 사과하십셔!","JPN":"はやく母ちゃんに謝ってくださいっす！","ENG":"Apologize to my mama!","TWN":"還不趕快向我媽媽道歉！"},"stage":{"bg":"VILLAGE1","bgm":"CSM_BATTLE_NORMAL0","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"LARA_NPC_NULL_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"TONFA_FLORA_SUMMER_NULL","face":"UNIT_IDLE"}}}},{"id":"L30_1","type":"dialog","speaker":"PMC_SUMMER_NULL_L","text":{"KOREA":"뭐?","JPN":"なに？","ENG":"What?","TWN":"什麼？"},"stage":{"bg":"VILLAGE1","bgm":"CSM_BATTLE_NORMAL0","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"PMC_SUMMER_NULL_L","face":"UNIT_IDLE"},"R":null}}},{"id":"L33_1","type":"dialog","speaker":"LARA_NPC_NULL_NULL","text":{"KOREA":"엄니요?","JPN":"母ちゃん？","ENG":"Your mama?","TWN":"媽媽？"},"stage":{"bg":"VILLAGE1","bgm":"CSM_BATTLE_NORMAL0","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"LARA_NPC_NULL_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"TONFA_FLORA_SUMMER_NULL","face":"UNIT_IDLE"}}}},{"id":"L36_1","type":"dialog","speaker":"SUYEON_COFFIN_SUMMER_NULL","text":{"KOREA":"저게…… 다 큰 딸이 있는 사람이라고?","JPN":"あれが……10代の娘がいる母親？","ENG":"That girl... woman... has a full-grown daughter?","TWN":"她…有這麼大的女兒？"},"stage":{"bg":"VILLAGE1","bgm":"CSM_BATTLE_NORMAL0","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SUYEON_COFFIN_SUMMER_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"MACHINEGAP_COFFIN_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L37_1","type":"dialog","speaker":"MACHINEGAP_COFFIN_NULL_NULL","text":{"KOREA":"도, 동요하지 말게. 부사장. 자네도 충분히 젊어 보이는 편이야.","JPN":"ど、動揺することない、副社長。君も十分若く見える方だぞ。","ENG":"S-stay calm, Vice President. You’re not so bad yourself.","TWN":"副總，穩住，你看起來也很年輕的。"},"stage":{"bg":"VILLAGE1","bgm":"CSM_BATTLE_NORMAL0","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SUYEON_COFFIN_SUMMER_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"MACHINEGAP_COFFIN_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L38_1","type":"dialog","speaker":"SUYEON_COFFIN_SUMMER_NULL","text":{"KOREA":"그, 그럼요. 저도 정글 같은 생존 경쟁에서 회사를 건사해 온 몸입니다. 고… 고작 천연 동안 정도에 흔들릴 리가 없죠.","JPN":"そ、そうですね。私だって弱肉強食社会で会社をやり繰りしてきた身です。た……たかが天然の童顔程度では動揺しません。","ENG":"O-of course. I’ve been keeping the company going in this dog-eat-dog world. Why would a natural-born babyface shock me?","TWN":"那…當然。好歹我也在險惡的職場中打滾這麼久，怎…怎麼可能因為區區的娃娃臉就失態呢。"},"stage":{"bg":"VILLAGE1","bgm":"CSM_BATTLE_NORMAL0","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SUYEON_COFFIN_SUMMER_NULL","face":"UNIT_PRIDE"},"C":null,"R":{"char_id":"MACHINEGAP_COFFIN_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L40_1","type":"dialog","speaker":"MONEMOTHER_NPC_NULL_NULL","text":{"KOREA":"모네야! 해변에 간다더니 여긴 왜 왔어! 위험하니까 어서 집에 들어가!","JPN":"モネ！　ビーチにいるはずのあなたがどうしてここにいるの？　危ないから家に入っていなさい！","ENG":"Mone! You said you were going to the beach, why are you here? It’s too dangerous, stay in the house!","TWN":"莫妮！你不是去海邊嗎？來這裡幹嘛？這裡很危險，你快點回家！"},"stage":{"bg":"VILLAGE1","bgm":"CSM_BATTLE_NORMAL0","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MONEMOTHER_NPC_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L41_1","type":"dialog","speaker":"TONFA_FLORA_SUMMER_NULL","text":{"KOREA":"싫슴다! 지금은 엄마 말 안 들을 검다!","JPN":"嫌っす！　今は母ちゃんのいうことは聞かないっす！","ENG":"No, mama! I’m not listening to you this time!","TWN":"不要！我現在不要聽媽媽的話！"},"stage":{"bg":"VILLAGE1","bgm":"CSM_BATTLE_NORMAL0","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"TONFA_FLORA_SUMMER_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L42_1","type":"dialog","speaker":"MONEMOTHER_NPC_NULL_NULL","text":{"KOREA":"엄마 말 안 들으면 집에 있는 동안 당근이랑 시금치만 준다?!","JPN":"お母さんの言うこと聞かない子には、ニンジンとほうれん草のおかずしか作ってあげないわよ？","ENG":"Listen to me right now, otherwise I’ll only cook you carrots and spinach for the rest of your stay!","TWN":"你不聽媽媽的話，等回家後就罰你每餐都只能吃三色豆！"},"stage":{"bg":"VILLAGE1","bgm":"CSM_BATTLE_NORMAL0","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MONEMOTHER_NPC_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L43_1","type":"dialog","speaker":"TONFA_FLORA_SUMMER_NULL","text":{"KOREA":"바, 반만 안 들을 검다!","JPN":"は、半分だけ聞くっす！","ENG":"I-I’ll only listen to half of what you say!","TWN":"我…聽一半！"},"stage":{"bg":"VILLAGE1","bgm":"CSM_BATTLE_NORMAL0","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"TONFA_FLORA_SUMMER_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L46_1","type":"dialog","speaker":"LARA_NPC_NULL_NULL","text":{"KOREA":"이제 어쩌죠! 분위기가 무지 살벌한데요?!","JPN":"どうしましょう？　なんか殺伐とした雰囲気ですよ！？","ENG":"What do we do now? It’s getting scarier and scarier!","TWN":"　　　　　　　"},"stage":{"bg":"VILLAGE1","bgm":"CSM_BATTLE_NORMAL0","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"LARA_NPC_NULL_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"SUYEON_COFFIN_SUMMER_NULL","face":"UNIT_DESPAIR"}}}},{"id":"L47_1","type":"dialog","speaker":"SUYEON_COFFIN_SUMMER_NULL","text":{"KOREA":"……주민들부터 대피시켜 주시죠. 휘말리면 위험해질지도 모르겠군요.","JPN":"……住民たちから避難させましょう。巻き込まれて危険な目に遭うかもしれません。","ENG":"... Please evacuate the villagers first. They might get caught up in the fight.","TWN":"…請先疏散居民吧，我怕他們掃到颱風尾會有危險。"},"stage":{"bg":"VILLAGE1","bgm":"CSM_BATTLE_NORMAL0","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"LARA_NPC_NULL_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"SUYEON_COFFIN_SUMMER_NULL","face":"UNIT_IDLE"}}}},{"id":"L2_1","type":"dialog","speaker":"PMC_SUMMER_NULL_L","text":{"KOREA":"쳇, 겁없이 덤비는 걸 보니 가정 교육 잘못 받은 카운터인가 보군.","JPN":"ちっ、その生意気な態度からして、家庭教育がなってないカウンターだな。","ENG":"Bah, I see you’re a bratty Counter who doesn’t listen to your mother.","TWN":"嗟，看她那副沒大沒小的樣子，一定是家庭教育有問題的制裁者。"},"stage":{"bg":"VILLAGE1","bgm":"CSM_BATTLE_NORMAL0","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"PMC_SUMMER_NULL_A","face":"UNIT_IDLE"},"C":{"char_id":"PMC_SUMMER_NULL_L","face":"UNIT_IDLE"},"R":{"char_id":"PMC_SUMMER_NULL_B","face":"UNIT_IDLE"}}}},{"id":"L3_1","type":"dialog","speaker":"PMC_SUMMER_NULL_L","text":{"KOREA":"좋아. 어른들 일에 함부로 끼어들면 어떻게 되는지 똑똑히 가르쳐 주마.","JPN":"いいぜ。大人の話にガキが割り込んだらどうなるか、きっちり教えてやる。","ENG":"Good. I’ll show you what happens when you don’t listen to the grown-ups.","TWN":"好吧，我要讓你知道，隨便插手大人的事情會怎麼樣！"},"stage":{"bg":"VILLAGE1","bgm":"CSM_BATTLE_NORMAL0","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"PMC_SUMMER_NULL_A","face":"UNIT_IDLE"},"C":{"char_id":"PMC_SUMMER_NULL_L","face":"UNIT_IDLE"},"R":{"char_id":"PMC_SUMMER_NULL_B","face":"UNIT_IDLE"}}}},{"id":"L4_1","type":"dialog","speaker":"PMC_SUMMER_NULL_L","text":{"KOREA":"다들 전투 준비! 저 꼬맹이를 본보기로 만들어 버려!","JPN":"皆、戦闘準備だ！　あのガキに大人の怖さを思い知らせてやれ！","ENG":"Everyone, get ready for a fight! Make an example of this girl!","TWN":"大家預備開戰，我們要殺雞儆猴！"},"stage":{"bg":"VILLAGE1","bgm":"CSM_BATTLE_NORMAL0","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"PMC_SUMMER_NULL_A","face":"UNIT_IDLE"},"C":{"char_id":"PMC_SUMMER_NULL_L","face":"UNIT_IDLE"},"R":{"char_id":"PMC_SUMMER_NULL_B","face":"UNIT_IDLE"}}}}]`);export{e as default};